1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	const quoteItems = (items: Item[]): number => {
15	  if (items.length === 0) return PROCESSING_FEE;
16	  const item = items[0];
17	  const base = BASE_PREMIUMS[item.type];
18	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
19	  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
20	};
21	
22	export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
23	  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
24	  return { results };
25	};
